import { useEffect, useReducer } from 'react';

const initialValue = {
  status: '',
  data: [],
  error: null,
};

function reducer(state, action) {
  switch (action.type) {
    case 'start':
      return {
        ...state,
        status: 'loading',
      };

    case 'success':
      return {
        status: 'success',
        data: action.payload,
      };

    case 'error':
      return {
        ...state,
        status: 'failed',
        error: action.payload,
      };

    default:
      return state;
  }
}

function useApi(URL) {
  const [{ status, data }, dispatch] = useReducer(reducer, initialValue);

  useEffect(() => {
    dispatch({ type: 'start' });

    const handleFetch = async () => {
      try {
        const response = await fetch(URL);

        const data = await response.json();

        dispatch({
          type: 'success',
          payload: data,
        });
      } catch (err) {
        dispatch({
          type: 'error',
          payload: err.message,
        });
      }
    };

    handleFetch();
  }, [URL]);

  return { status, data };
}

export default useApi;

import { createContext, useState } from 'react';

const StoreContext = createContext({
  data: [],
  addData: () => {},
  removeData: () => {},
  deleteData: () => {},
});

function StoreCartProviderHelper({ children }) {
  const [selectedData, setSelectedDate] = useState([]);

  const handleAdd = (itm) => {
    setSelectedDate((previousSelected) => {
      return [
        ...previousSelected,
        {
          ...itm,
          quantity: 1,
        },
      ];
    });
  };

  const handleReduce = (id) => {
    setSelectedDate((previousSelected) =>
      previousSelected.map((item) =>
        item.id === id
          ? {
              ...item,
              quantity: item.quantity - 1,
            }
          : item
      )
    );
  };

  const handleDelete = (id) => {
    setSelectedDate((previousSelected) =>
      previousSelected.filter((itm) => itm.id !== id)
    );
  };

  const valueItem = {
    data: selectedData,
    addData: handleAdd,
    removeData: handleReduce,
    deleteData: handleDelete,
  };

  return (
    <StoreContext.Provider value={valueItem}>
      {children}
    </StoreContext.Provider>
  );
}

export default StoreCartProviderHelper;

import React from 'react';

import {
  createBrowserRouter,
  RouterProvider,
  Outlet,
} from 'react-router-dom';

function Parent() {
  return (
    <div>
      <Outlet />
    </div>
  );
}

const router = createBrowserRouter([
  {
    path: '/',
    element: <Parent />,
    children: [
      {
        path: 'dashboard',
        element: <h1>Dashboard</h1>,
      },
    ],
  },
]);

function AppRouter() {
  return <RouterProvider router={router} />;
}

export default AppRouter;

import {
  motion,
  AnimatePresence,
} from 'framer-motion';

function FramerHelper({ children }) {
  const modalVariants = {
    hidden: {
      scale: 0.8,
    },

    visible: {
      scale: 1,

      transition: {
        type: 'spring',
        stiffness: 200,
        damping: 20,
      },
    },

    exit: {
      scale: 0.8,

      transition: {
        duration: 0.2,
      },
    },
  };

  return (
    <AnimatePresence>
      <motion.div
        variants={modalVariants}
        initial='hidden'
        animate='visible'
        exit='exit'
      >
        {children}
      </motion.div>
    </AnimatePresence>
  );
}

export default FramerHelper;
